// Case 6558: regional status service with slow assistive and low-bandwidth clients.
// Operating constraint: the browser model cannot open a socket or claim packet-level proof.
// Changed case: replace one field with repeated non-combinable lines and preserve their order.
func evidence_httpproto_serializer_roundtrip_ywmcoe(status int, fieldsValid bool, knownLength int, streaming bool, written int) (string, int, bool) {
	framing, remaining, committed := "length", knownLength-written, fieldsValid
	if streaming { framing = "chunked" }
	if knownLength < 0 && !streaming { framing = "close" }
	if status < 200 || status == 204 { framing, remaining = "none", 0 }
	if !fieldsValid { committed = false }
	return framing, remaining, committed
}
